  1→//! Structured error parsing for chat error messages.
  2→//!
  3→//! Converts raw error strings from agent runners / LLM providers into
  4→//! structured JSON payloads that the frontend can render directly.
  5→
  6→use serde_json::Value;
  7→
  8→/// Parse a raw error string into a structured error object with `type`, `icon`,
  9→/// `title`, `detail`, and optionally `provider`, `resetsAt`, and
 10→/// `retryAfterMs` fields.
 11→pub fn parse_chat_error(raw: &str, provider_name: Option<&str>) -> Value {
 12→    let mut error = try_parse_known_error(raw);
 13→
 14→    if let Some(name) = provider_name
 15→        && let Some(obj) = error.as_object_mut()
 16→    {
 17→        obj.insert("provider".into(), Value::String(name.to_string()));
 18→    }
 19→
 20→    error
 21→}
 22→
 23→fn try_parse_known_error(raw: &str) -> Value {
 24→    // Max iterations reached — before JSON parsing since the message is plain text.
 25→    if raw.contains("agent loop exceeded max iterations") {
 26→        let limit = raw
 27→            .rsplit('(')
 28→            .next()
 29→            .and_then(|s| s.trim_end_matches(')').trim().parse::<u64>().ok())
 30→            .unwrap_or(25);
 31→        let mut err = build_error(
 32→            "max_iterations_reached",
 33→            "\u{1F504}",
 34→            "Iteration limit reached",
 35→            &format!(
 36→                "The agent stopped after {} iterations. You can continue if needed.",
 37→                limit
 38→            ),
 39→            None,
 40→            None,
 41→            Some(serde_json::json!({ "limit": limit })),
 42→        );
 43→        if let Some(obj) = err.as_object_mut() {
 44→            obj.insert("canContinue".into(), Value::Bool(true));
 45→        }
 46→        return err;
 47→    }
 48→
 49→    let http_status = extract_http_status(raw);
 50→
 51→    // Try to extract embedded JSON from the error string.
 52→    if let Some(start) = raw.find('{')
 53→        && let Ok(parsed) = serde_json::from_str::<Value>(&raw[start..])
 54→    {
 55→        let err_obj = parsed.get("error").unwrap_or(&parsed);
 56→
 57→        // Usage limit
 58→        if matches_type_or_message(err_obj, "usage_limit_reached", "usage limit") {
 59→            let plan_type = err_obj
 60→                .get("plan_type")
 61→                .and_then(|v| v.as_str())
 62→                .unwrap_or("current");
 63→            let resets_at = extract_resets_at(err_obj);
 64→            return build_error(
 65→                "usage_limit_reached",
 66→                "",
 67→                "Usage limit reached",
 68→                &format!("Your {} plan limit has been reached.", plan_type),
 69→                resets_at,
 70→                None,
 71→                Some(serde_json::json!({ "planType": plan_type })),
 72→            );
 73→        }
 74→
 75→        // Billing / quota exhaustion (not transient rate limiting).
 76→        if is_insufficient_quota_error(err_obj, raw) {
 77→            let detail = err_obj.get("message").and_then(|v| v.as_str()).unwrap_or(
 78→                "Your account quota is exhausted. Add funds or switch providers and try again.",
 79→            );
 80→            return build_error(
 81→                "billing_exhausted",
 82→                "\u{26A0}\u{FE0F}",
 83→                "Insufficient quota",
 84→                detail,
 85→                None,
 86→                None,
 87→                None,
 88→            );
 89→        }
 90→
 91→        // Rate limit
 92→        if matches_type_or_message(err_obj, "rate_limit_exceeded", "rate limit")
 93→            || matches_type_or_message(err_obj, "rate_limit_exceeded", "quota exceeded")
 94→            || http_status == Some(429)
 95→        {
 96→            let detail = err_obj
 97→                .get("message")
 98→                .and_then(|v| v.as_str())
 99→                .unwrap_or("Too many requests. Please wait a moment.");
100→            let resets_at = extract_resets_at(err_obj);
101→            let retry_after_ms = extract_retry_after_ms(raw, err_obj);
102→            return build_error(
103→                "rate_limit_exceeded",
104→                "\u{26A0}\u{FE0F}",
105→                "Rate limited",
106→                detail,
107→                resets_at,
108→                retry_after_ms,
109→                None,
110→            );
111→        }
112→
113→        // Generic JSON error with a message field
114→        if let Some(msg) = extract_message(err_obj)
115→            && is_unsupported_model_message(msg)
116→        {
117→            return build_error(
118→                "unsupported_model",
119→                "\u{26A0}\u{FE0F}",
120→                "Model not supported",
121→                msg,
122→                None,
123→                None,
124→                None,
125→            );
126→        }
127→
128→        // Generic JSON error with a message field
129→        if let Some(msg) = err_obj.get("message").and_then(|v| v.as_str()) {
130→            return build_error(
131→                "api_error",
132→                "\u{26A0}\u{FE0F}",
133→                "Error",
134→                msg,
135→                None,
136→                None,
137→                None,
138→            );
139→        }
140→    }
141→
142→    // Check for HTTP status codes in the raw message.
143→    if is_insufficient_quota_error(&Value::Null, raw) {
144→        return build_error(
145→            "billing_exhausted",
146→            "\u{26A0}\u{FE0F}",
147→            "Insufficient quota",
148→            raw,
149→            None,
150→            None,
151→            None,
152→        );
153→    }
154→
155→    if let Some(code) = http_status {
156→        match code {
157→            401 | 403 => {
158→                return build_error(
159→                    "auth_error",
160→                    "\u{1F512}",
161→                    "Authentication error",
162→                    "Your session may have expired or credentials are invalid.",
163→                    None,
164→                    None,
165→                    None,
166→                );
167→            },
168→            429 => {
169→                let retry_after_ms = extract_retry_after_ms(raw, &Value::Null);
170→                return build_error(
171→                    "rate_limit_exceeded",
172→                    "",
173→                    "Rate limited",
174→                    "Too many requests. Please wait a moment and try again.",
175→                    None,
176→                    retry_after_ms,
177→                    None,
178→                );
179→            },
180→            code if code >= 500 => {
181→                return build_error(
182→                    "server_error",
183→                    "\u{1F6A8}",
184→                    "Server error",
185→                    "The upstream provider returned an error. Please try again later.",
186→                    None,
187→                    None,
188→                    None,
189→                );
190→            },
191→            _ => {},
192→        }
193→    }
194→
195→    if is_unsupported_model_message(raw) {
196→        return build_error(
197→            "unsupported_model",
198→            "\u{26A0}\u{FE0F}",
199→            "Model not supported",
200→            raw,
201→            None,
202→            None,
203→            None,
204→        );
205→    }
206→
207→    // Default: pass through raw message.
208→    build_error(
209→        "unknown",
210→        "\u{26A0}\u{FE0F}",
211→        "Error",
212→        raw,
213→        None,
214→        None,
215→        None,
216→    )
217→}
218→
219→fn extract_message(obj: &Value) -> Option<&str> {
220→    obj.get("detail")
221→        .and_then(|v| v.as_str())
222→        .or_else(|| obj.get("message").and_then(|v| v.as_str()))
223→        .or_else(|| {
224→            obj.get("error")
225→                .and_then(|v| v.get("message"))
226→                .and_then(|v| v.as_str())
227→        })
228→        .or_else(|| {
229→            obj.get("error")
230→                .and_then(|v| v.get("detail"))
231→                .and_then(|v| v.as_str())
232→        })
233→}
234→
235→fn is_unsupported_model_message(message: &str) -> bool {
236→    let lower = message.to_ascii_lowercase();
237→
238→    // Non-chat modality errors (audio, image, video models probed via chat
239→    // completion). These don't mention "model" or "supported" but clearly
240→    // indicate the model isn't meant for /v1/chat/completions.
241→    if lower.contains("input content or output modality contain audio")
242→        || lower.contains("requires audio")
243→    {
244→        return true;
245→    }
246→
247→    let has_model = lower.contains("model");
248→    let unsupported = lower.contains("not supported")
249→        || lower.contains("unsupported")
250→        || lower.contains("not available")
251→        || lower.contains("not a chat model")
252→        || lower.contains("does not support chat")
253→        || lower.contains("only supported in v1/responses")
254→        || lower.contains("v1/chat/completions");
255→    has_model && unsupported
256→}
257→
258→fn matches_type_or_message(obj: &Value, type_str: &str, message_substr: &str) -> bool {
259→    if let Some(t) = obj.get("type").and_then(|v| v.as_str())
260→        && t == type_str
261→    {
262→        return true;
263→    }
264→    if let Some(m) = obj.get("message").and_then(|v| v.as_str())
265→        && m.to_lowercase().contains(message_substr)
266→    {
267→        return true;
268→    }
269→    false
270→}
271→
272→fn is_insufficient_quota_error(obj: &Value, raw: &str) -> bool {
273→    if obj
274→        .get("type")
275→        .and_then(|v| v.as_str())
276→        .is_some_and(|t| t.eq_ignore_ascii_case("insufficient_quota"))
277→    {
278→        return true;
279→    }
280→    if obj
281→        .get("code")
282→        .and_then(|v| v.as_str())
283→        .is_some_and(|c| c.eq_ignore_ascii_case("insufficient_quota"))
284→    {
285→        return true;
286→    }
287→    if obj
288→        .get("message")
289→        .and_then(|v| v.as_str())
290→        .is_some_and(|m| {
291→            let lower = m.to_ascii_lowercase();
292→            lower.contains("insufficient_quota")
293→                || (lower.contains("current quota") && lower.contains("billing"))
294→        })
295→    {
296→        return true;
297→    }
298→
299→    raw.to_ascii_lowercase().contains("insufficient_quota")
300→}
301→
302→fn extract_resets_at(obj: &Value) -> Option<u64> {
303→    obj.get("resets_at").and_then(|v| v.as_u64())
304→}
305→
306→fn parse_retry_delay_ms_from_fragment(
307→    fragment: &str,
308→    unit_default_ms: bool,
309→    max_ms: u64,
310→) -> Option<u64> {
311→    let start = fragment.find(|c: char| c.is_ascii_digit())?;
312→    let tail = &fragment[start..];
313→    let digits_len = tail.chars().take_while(|c| c.is_ascii_digit()).count();
314→    if digits_len == 0 {
315→        return None;
316→    }
317→    let amount = tail[..digits_len].parse::<u64>().ok()?;
318→    let unit = tail[digits_len..].trim_start();
319→
320→    let ms = if unit.starts_with("ms") || unit.starts_with("millisecond") {
321→        amount
322→    } else if unit.starts_with("sec") || unit.starts_with("second") || unit.starts_with('s') {
323→        amount.saturating_mul(1_000)
324→    } else if unit.starts_with("min") || unit.starts_with("minute") || unit.starts_with('m') {
325→        amount.saturating_mul(60_000)
326→    } else if unit_default_ms {
327→        amount
328→    } else {
329→        amount.saturating_mul(1_000)
330→    };
331→
332→    Some(ms.clamp(1, max_ms))
333→}
334→
335→fn extract_retry_after_ms(raw: &str, err_obj: &Value) -> Option<u64> {
336→    const MAX_RETRY_AFTER_MS: u64 = 86_400_000;
337→
338→    if let Some(ms) = err_obj.get("retry_after_ms").and_then(|v| v.as_u64()) {
339→        return Some(ms.clamp(1, MAX_RETRY_AFTER_MS));
340→    }
341→    if let Some(seconds) = err_obj.get("retry_after_seconds").and_then(|v| v.as_u64()) {
342→        return Some(seconds.saturating_mul(1_000).clamp(1, MAX_RETRY_AFTER_MS));
343→    }
344→    if let Some(seconds) = err_obj.get("retry_after").and_then(|v| v.as_u64()) {
345→        return Some(seconds.saturating_mul(1_000).clamp(1, MAX_RETRY_AFTER_MS));
346→    }
347→
348→    let lower = raw.to_ascii_lowercase();
349→    for (needle, default_ms) in [
350→        ("retry_after_ms=", true),
351→        ("retry-after-ms=", true),
352→        ("retry_after=", false),
353→        ("retry-after:", false),
354→        ("retry after ", false),
355→        ("retry in ", false),
356→    ] {
357→        if let Some(idx) = lower.find(needle) {
358→            let fragment = &lower[idx + needle.len()..];
359→            if let Some(ms) =
360→                parse_retry_delay_ms_from_fragment(fragment, default_ms, MAX_RETRY_AFTER_MS)
361→            {
362→                return Some(ms);
363→            }
364→        }
365→    }
366→
367→    None
368→}
369→
370→fn extract_http_status(raw: &str) -> Option<u16> {
371→    // Match patterns like "HTTP 429", "status 503", "status: 401", "status=429"
372→    let patterns = ["HTTP ", "status= ", "status=", "status: ", "status "];
373→    for pat in &patterns {
374→        if let Some(idx) = raw.find(pat) {
375→            let after = &raw[idx + pat.len()..];
376→            let digits: String = after.chars().take_while(|c| c.is_ascii_digit()).collect();
377→            if let Ok(code) = digits.parse::<u16>() {
378→                return Some(code);
379→            }
380→        }
381→    }
382→    None
383→}
384→
385→fn build_error(
386→    error_type: &str,
387→    icon: &str,
388→    title: &str,
389→    detail: &str,
390→    resets_at: Option<u64>,
391→    retry_after_ms: Option<u64>,
392→    detail_params: Option<Value>,
393→) -> Value {
394→    let mut obj = serde_json::json!({
395→        "type": error_type,
396→        "icon": icon,
397→        "title": title,
398→        "detail": detail,
399→    });
400→    if let Some(map) = obj.as_object_mut() {
401→        let (title_key, detail_key) = translation_keys_for(error_type);
402→        if let Some(key) = title_key {
403→            map.insert("title_key".into(), Value::String(key.to_string()));
404→        }
405→        if let Some(key) = detail_key {
406→            map.insert("detail_key".into(), Value::String(key.to_string()));
407→        }
408→        if let Some(params) = detail_params {
409→            map.insert("detail_params".into(), params);
410→        }
411→        if let Some(ts) = resets_at {
412→            // Send as milliseconds for the frontend.
413→            map.insert("resetsAt".into(), Value::Number((ts * 1000).into()));
414→        }
415→        if let Some(delay) = retry_after_ms {
416→            map.insert("retryAfterMs".into(), Value::Number(delay.into()));
417→        }
418→    }
419→    obj
420→}
421→
422→fn translation_keys_for(error_type: &str) -> (Option<&'static str>, Option<&'static str>) {
423→    match error_type {
424→        "usage_limit_reached" => (
425→            Some("errors:chat.usageLimitReached.title"),
426→            Some("errors:chat.usageLimitReached.detail"),
427→        ),
428→        "rate_limit_exceeded" => (
429→            Some("errors:chat.rateLimited.title"),
430→            Some("errors:chat.rateLimited.detail"),
431→        ),
432→        "auth_error" => (
433→            Some("errors:chat.authError.title"),
434→            Some("errors:chat.authError.detail"),
435→        ),
436→        "server_error" => (
437→            Some("errors:chat.serverError.title"),
438→            Some("errors:chat.serverError.detail"),
439→        ),
440→        "unsupported_model" => (Some("errors:chat.unsupportedModel.title"), None),
441→        "billing_exhausted" => (
442→            Some("errors:chat.billingExhausted.title"),
443→            Some("errors:chat.billingExhausted.detail"),
444→        ),
445→        "max_iterations_reached" => (
446→            Some("errors:chat.maxIterationsReached.title"),
447→            Some("errors:chat.maxIterationsReached.detail"),
448→        ),
449→        "api_error" | "unknown" => (Some("errors:generic.title"), None),
450→        _ => (None, None),
451→    }
452→}
