        assert!(!is_chat_capable_model("openai::gpt-image-1-mini"));
        assert!(!is_chat_capable_model("openai::gpt-4o-mini-tts"));
        assert!(!is_chat_capable_model(
            "custom-openrouter::openai/gpt-image-1-mini"
        ));
    }

