        assert_eq!(
            openai_ids.len(),
            openai_models.len(),
            "duplicate OpenAI model IDs found"
        );

        for models in [
            ANTHROPIC_MODELS,
            MISTRAL_MODELS,
            CEREBRAS_MODELS,
            MINIMAX_MODELS,
            ZAI_MODELS,
            MOONSHOT_MODELS,
            GEMINI_MODELS,
        ] {
            let mut ids: Vec<&str> = models.iter().map(|(id, _)| *id).collect();
            ids.sort();
            ids.dedup();
            assert_eq!(ids.len(), models.len(), "duplicate model IDs found");
        }
    }

