        let sse = "\
            data: {\"type\":\"response.output_text.delta\",\"delta\":\"cached\"}\n\n\
            data: {\"type\":\"response.completed\",\"response\":{\"usage\":{\"input_tokens\":100,\"output_tokens\":10,\"input_tokens_details\":{\"cached_tokens\":80}}}}\n\n";
